var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"1개월 뒤","JPN":"1か月後","ENG":"1 month later","TWN":"1個月後","THA":"1 เดือน ผ่านไป","VTN":"1 tháng sau","SCN":"1个月后","DEU":"1 Monat später","FRA":"1 mois plus tard"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"진지 건설을 서둘러! 여길 거점으로 제7지구의 방위선을 구축한다!","JPN":"陣地建設を急げ！　ここを拠点に、第7地区の防衛線を築く！","ENG":"Hurry up with the base construction! We will build the 7th Defense Line with this location as the base!","TWN":"加快建設基地！以這裡為據點，修築第七區的防線！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"자재 보급은 아직이야? 뼈대부터 세워야 기질 세우든 말든 할 거 아니야!","JPN":"資材の補給はまだなのか？　骨組みができなきゃ基地なんか建てられないぞ！","ENG":"Are the materials here yet? We need to finish the framing if we're gonna build a base here!","TWN":"材料補給還沒到嗎？基礎材料都沒到，還談什麼建基地！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"여기 봐! 아직 의약품이 남아있어! 이 근처에 원래 약국이 있었을지도 몰라!","JPN":"これを見ろ！　まだ医薬品が残っている！　この辺りに薬局があったのかもな！","ENG":"Hey, look! There is still some medicine left! Maybe there was a pharmacy around here or something!","TWN":"快看！還有些剩餘的醫藥品！這附近說不定本來就是藥店呢！"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"……아니요, 이 이상 건설 일정을 당기는 건 무리입니다.","JPN":"……いいえ、これ以上建設の日程を早めることは不可能です。","ENG":"...No, I'm afraid not. We cannot advance the construction timeline any further.","TWN":"……不行，工程的時間不能再提前了。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"……후우, 알겠습니다. 그건 제 권한으로 예산을 조금 더 확보해보죠.","JPN":"……はぁ、わかりました。そちらは私の権限でもう少し予算確保を取り計らってみます。","ENG":"*Sigh...* Understood. I'll see what I can do to secure more funding.","TWN":"……好，我明白了。我會用我的權限再申請一些預算。"},"stage":{"bg":"NEWTOWN","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"자, 여기 주문하신 시원한 물 나왔어요, 손님~","JPN":"はい、こちらご注文の冷水ですよ、お客様～","ENG":"Hello! Your ice-cold water is here!","TWN":"這是你點的冰水，客人～"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"휴우, 고마워요. 시영 씨. 덕분에 한 숨 돌리겠네요.","JPN":"ふう、ありがとうございます、シノンさん。おかげで一息つけそうです。","ENG":"Whew, thank you, Shiyoung. You're a lifesaver.","TWN":"呼，謝謝你，時雨。我終於能鬆一口氣了。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이런 활기찬 분위기, 굉장히 오랜만인 것 같은데요?","JPN":"こういうにぎやかな雰囲気は、かなり久しぶりだと思いませんか？","ENG":"It's been a long time since it was this bustling anywhere, right?","TWN":"好久沒有感受到這種活力滿滿的氣氛了吧？"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"땀범벅인데도 다들 웃고 있어서 보기 좋네요.","JPN":"汗だくになりながらもみんな笑顔で、見ていて微笑ましいですね。","ENG":"It's nice to see people smile even though they're sweating.","TWN":"大家雖然累得滿頭大汗，卻都開心地笑著，真好。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그야, 이곳이 네피림 사태 이후 인류가 탈환한 첫 번째 거점이니까요.","JPN":"ここはネフィリム事件発生以来、人類が初めて奪還した拠点ですからね。","ENG":"That's because this is the first base mankind has retaken since the Nephil incident.","TWN":"那是因為這裡是諾菲力事件之後，人類奪回的第一個據點。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"여길 기반으로 제7 방위선이 구축되면, 내일은 분명 오늘보다 안전해질 거예요.","JPN":"ここを基点に第7防衛線が築かれれば、きっと明日は今日より安全になります。","ENG":"If we start building the 7th Defense Line here, it will be safer tomorrow than it was today.","TWN":"以這裡為基礎修築的第七防線，將來一定比現在更加安全。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"그렇게 조금씩 힘을 길러가면, 어쩌면 미래에는 우리 스스로 멸망을 막아낼 수도 있겠죠.","JPN":"そうやって少しずつ力をつけていけば、もしかすると将来には自分たちの力で滅亡を食い止めることができるかもしれません。","ENG":"And perhaps, by strengthening ourselves one day at a time, we may be able to prevent disasters in the future.","TWN":"這樣一點點地累積力量，說不定未來我們靠自己就能阻止滅亡。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"아니, 제가 그렇게 만들겠어요, 반드시.","JPN":"いいえ、私がそうしてみせます、必ず。","ENG":"Rather, we will prevent it. I'll make it so.","TWN":"不，我們會阻止的，一定。"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"LONE_EXILER_NPC_QM","text":{"KOREA":"소령!! 카린 웡 소령!!","JPN":"少佐！！　カリン・ウォン少佐！！","ENG":"Major!! Major Wong!!","TWN":"少校！！卡琳少校！！"},"stage":{"bg":"NEWTOWN","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};